#include <ranges>
#include <vector>
#include <print>
int main() {
    std::vector<int> nums = {-3, -1, 0, 2, 4, 6, 8};

    // C++23: one-liner
    auto evens = nums
        | std::views::filter([](int x){ return x > 0; })
        | std::views::transform([](int x){ return x * x; })
        | std::ranges::to<std::vector>();

    std::println("{}", evens);
}

#include <ranges>
#include <vector>
#include <set>
#include <string>
#include <print>
int main() {
    std::vector<int> v = {3, 1, 4, 1, 5, 9, 2, 6, 5};

    // deduplicate via set
    auto unique = v | std::ranges::to<std::set>();
    std::println("unique: {}", unique);

    // back to sorted vector
    auto sorted_v = unique | std::ranges::to<std::vector>();
    std::println("sorted: {}", sorted_v);

    // chars to string
    auto letters = std::views::iota(0, 5)
        | std::views::transform([](int i){ return static_cast<char>('a' + i); })
        | std::ranges::to<std::string>();
    std::println("letters: {}", letters);
}

#include <ranges>
#include <vector>
#include <string>
#include <print>
int main() {
    std::vector<std::string> words = {"hello world", "foo bar", "cpp23"};

    // split each word by space, collect into vector<vector<string>>
    auto split_words = words
        | std::views::transform([](const std::string& s) {
            return s | std::views::split(' ')
                     | std::views::transform([](auto r){
                           return std::string(r.begin(), r.end());
                       })
                     | std::ranges::to<std::vector>();
          })
        | std::ranges::to<std::vector>();

    for (const auto& parts : split_words) {
        std::println("{}", parts);
    }
}
